import React from "react";
import styles from "./cart-wrapper.module.css";
import TableHeading from "../table-heading";
import CartItem from "../cart-item";
import CartSubtotal from "../cart-subtotal";
import Button from "../../button";

import { useAppSelector } from "../../../app/hooks";

const CartWrapper = () => {
  const cart = useAppSelector((state) => state.cart);

  return (
    <div className={styles.cart_wrapper}>
      <div className="container">
        <div className="cart_top">
          <TableHeading
            col1="Product"
            col2="Price"
            col3="Quantity"
            col4="Total"
          />
        </div>
        <div className="cart_body">
          {cart.items.map((cartItem) => (
            <CartItem
              key={cartItem.id}
              product={{
                id: cartItem.id,
                imgSrc: cartItem.img,
                title: cartItem.name,
                price: cartItem.price,
              }}
            />
          ))}
        </div>
        <div className={styles.cart_bottom}>
          <CartSubtotal
            title="Sub-total"
            price={9.99} // You should calculate the actual subtotal here
            VAT="Tax and shipping cost will be calculated later"
          />
          <Button text="Check-out" to="/checkout" />
        </div>
      </div>
    </div>
  );
};

export default CartWrapper;






